  "breach-of-the-accountability-obligation-by-mcst-4599": {
    "organisation": "The Management Corporation - Strata Title Plan No. 4599",
    "case_number": "DP-2405-C2318",
    "citation": "[2025] SGPDPC 3",
    "decision_date": "19 May 2025",
    "industry": "Property Management / Condominium Management",
    "overview": "A management corporation failed to develop and implement data protection policies and procedures, and did not designate a data protection officer, resulting in improper handling of a CCTV access request and loss of footage. The case demonstrates the importance of organisations maintaining accountability and preparedness when handling personal data requests, particularly when delegating duties to third parties.",
    "pdpa_sections": [
      "s.21",
      "s.22A",
      "s.11(3)",
      "s.12"
    ],
    "obligations": [
      "Access Obligation",
      "Accountability Obligation"
    ],
    "individuals_affected": null,
    "root_cause": "The Organisation failed to develop contextualised data protection policies and procedures, did not appoint a data protection officer, and gave no written instructions to its managing agents or security company on handling access requests. This systemic failure prevented proper preservation and timely retrieval of CCTV footage.",
    "outcome": "The Commission directed the Organisation to: (a) develop and implement policies to meet PDPA obligations; (b) establish procedures for managing CCTV footage upon access requests; (c) communicate these policies and procedures to data intermediaries and contractors; and (d) provide a written update within 7 days of completion, all within 60 days.",
    "penalty": null,
    "mitigating": [
      "Organisation appointed a DPO after the incident",
      "KFPFM consulted the Organisation and sought instructions on the access request"
    ],
    "aggravating": [
      "Complete absence of data protection policies",
      "No designated data protection officer at time of incident",
      "Failure to provide written instructions to third parties handling personal data"
    ],
    "_id": "breach-of-the-accountability-obligation-by-mcst-4599"
  },
