  "no-breach-of-the-consent-obligation-by-institute-of-mental-health": {
    "organisation": "Institute of Mental Health",
    "case_number": "DP-2404-C2257",
    "citation": "[2025] SGPDPC 1",
    "decision_date": "21 May 2025",
    "industry": "Healthcare / Mental Health",
    "overview": "A research officer approached a patient in the clinic waiting area to recruit them for a study, having identified the patient by name using information provided by the attending doctor. The complainant alleged unauthorised use of personal data without consent. The Commission found the organisation had obtained implied consent through notification and did not breach the Consent Obligation, though it lacked proper opt-out mechanisms required for deemed consent by notification.",
    "pdpa_sections": [
      "s.13(a)",
      "s.14(1)",
      "s.15A"
    ],
    "obligations": [
      "Consent Obligation"
    ],
    "individuals_affected": null,
    "root_cause": "The organisation displayed a notification in high-traffic clinic areas since 2014 stating it may use personal data for research recruitment, but did not provide patients with clear information about how to opt out or notify the organisation of their refusal to consent.",
    "outcome": "The Commission found the organisation compliant with the Consent Obligation based on implied consent. However, it cannot rely on deemed consent by notification due to failure to alert individuals to opt-out mechanisms. The organisation has voluntarily implemented revised guidelines requiring express consent be sought from the clinical team before direct research recruitment contact using medical information.",
    "penalty": null,
    "mitigating": [
      "Voluntary process review and revised guidelines",
      "Cooperative during investigation"
    ],
    "aggravating": [],
    "_id": "no-breach-of-the-consent-obligation-by-institute-of-mental-health"
  },
