  "breach-of-the-protection-obligation-by-ezynetic": {
    "organisation": "Ezynetic Pte. Ltd.",
    "case_number": "DP-2406-C2585",
    "citation": "[2025] SGPDPCS 2",
    "decision_date": null,
    "industry": "Software-as-a-Service (SaaS) provider for licensed moneylenders",
    "overview": "Ezynetic's servers were infected by ransomware on 24 June 2024, resulting in the exfiltration of personal data of 190,589 individuals which was posted for sale on the dark web. The company failed to implement reasonable security arrangements including weak password controls on a critical system administrator account and the absence of periodic vulnerability assessments.",
    "pdpa_sections": [
      "s.24"
    ],
    "obligations": [
      "Protection Obligation"
    ],
    "individuals_affected": "190589",
    "root_cause": "The threat actor exploited a vulnerable web service application to gain access to and control of the system administrator (SA) account, which had inadequate access controls and a weak, brute-force-susceptible password (p@ssword1 or Password@1). The organisation had not conducted periodic vulnerability assessments or penetration testing.",
    "outcome": "Financial penalty of $17,500 payable within 30 days. Directed to obtain CSA's Cyber Trustmark Certification for its new IT network within 9 months and report to the Commission within 14 days of completion.",
    "penalty": 17500,
    "mitigating": [
      "Cooperative during investigation",
      "Voluntarily admitted to breach under Expedited Decision Procedure",
      "First instance of non-compliance with PDPA",
      "Promptly implemented comprehensive remedial actions including network rebuild and cloud migration"
    ],
    "aggravating": [
      "Large number of individuals affected (190,589)",
      "Sensitive personal data including NRIC numbers and financial information",
      "Organisation is a SaaS provider with technical expertise expected to implement cybersecurity measures",
      "Critical vulnerabilities in a well-known SQL server account"
    ],
    "_id": "breach-of-the-protection-obligation-by-ezynetic"
  },
