  "breach-of-the-protection-obligation-by-hmi-institute-of-health-science": {
    "organisation": "HMI Institute of Health Science Pte. Ltd.",
    "case_number": "DP-2405-C2321",
    "citation": "[2024] SGPDPCS 5",
    "decision_date": null,
    "industry": "Healthcare training provider",
    "overview": "HMI Institute inadvertently made an Excel file containing personal data of 761 individuals publicly available on the Internet after failing to properly decommission a Students' Career Portal in December 2019. The file remained in the organisation's web directory with no access controls, allowing search engines to index and publicly expose sensitive personal data including NRIC numbers, addresses, and contact information.",
    "pdpa_sections": [
      "s.24"
    ],
    "obligations": [
      "Protection Obligation"
    ],
    "individuals_affected": "761",
    "root_cause": "The organisation did not exercise adequate oversight over its vendor during the decommissioning of the Portal and failed to verify that personal data had been properly deleted and was no longer accessible. Additionally, the Excel file remained in the web directory with no access controls to prevent search engine indexing.",
    "outcome": "The organisation is required to pay a financial penalty of $10,000 within 30 days and is directed to: (a) create and maintain a personal data asset inventory; (b) put in place a documented vendor management policy; (c) conduct vulnerability assessment and penetration testing; and (d) submit a completion report within 60 days.",
    "penalty": 10000,
    "mitigating": [
      "Organisation was cooperative during investigation",
      "Organisation voluntarily admitted to breach under Expedited Decision Procedure"
    ],
    "aggravating": [
      "Second contravention of the PDPA by the organisation",
      "Sensitive personal data disclosed including NRIC numbers and addresses"
    ],
    "_id": "breach-of-the-protection-obligation-by-hmi-institute-of-health-science"
  },
