  "breach-of-the-protection-and-accountability-obligations-by-consumers-association-of-singapore": {
    "organisation": "Consumers' Association of Singapore (CASE)",
    "case_number": "DP-2210-C0303 & DP-2306-C1172",
    "citation": "[2024] SGPDPC 4",
    "decision_date": "09 July 2024",
    "industry": "Non-profit, non-governmental organisation (consumer advocacy and dispute resolution)",
    "overview": "CASE suffered two separate data breaches involving phishing emails sent to consumers. Incident 1 involved unauthorised access to two email accounts through compromised employee credentials, exposing 22,542 email addresses. Incident 2 involved exfiltration of personal data during a data migration exercise, affecting approximately 12,218 individuals. The organisation failed to implement adequate password policies, staff training, and security measures required under the PDPA.",
    "pdpa_sections": [
      "s.24",
      "s.12(a)"
    ],
    "obligations": [
      "Protection Obligation",
      "Accountability Obligation"
    ],
    "individuals_affected": "12218",
    "root_cause": "The organisation failed to enforce its own password complexity policy, did not implement mandatory password change requirements (passwords unchanged for nearly 4 years), lacked ICT security policies, did not conduct regular staff training on cybersecurity risks, and failed to include clear security responsibilities in vendor contracts during data migration.",
    "outcome": "CASE is directed to: (1) pay a financial penalty of $20,000 within 30 days; (2) review and update policies relevant to personal data protection, including ICT policy and password policy; (3) rectify all security gaps identified by the private forensic expert including applying patches, enabling security settings, and ensuring proper system configuration; (4) update the Commission within 1 week of completion.",
    "penalty": 20000,
    "mitigating": [
      "Organisation took prompt actions after being alerted to mitigate the incidents",
      "Investigations handled under Expedited Breach Decision Procedure with full admission of facts",
      "Organisation was cooperative with Commission investigations",
      "No monetary losses suffered by individuals in Incident 2"
    ],
    "aggravating": [
      "Breach continued for more than three years",
      "Large volume of personal data affected (22,542 email addresses in Incident 1; 12,218 individuals in Incident 2)",
      "Dearth of basic policies or security measures",
      "No security reviews conducted in 3 years preceding Incident 1",
      "More than 30 out of 45 computers had critical and high-risk vulnerabilities",
      "Phishing emails in Incident 2 used exfiltrated complaint details to appear more convincing, exposing individuals to greater financial loss risk",
      "Three consumers suffered significant monetary losses (S$900, S$68,000, S$149,000) in Incident 1"
    ],
    "_id": "breach-of-the-protection-and-accountability-obligations-by-consumers-association-of-singapore"
  },
