  "breach-of-the-protection-obligation-by-keppel-telecommunications-transportation": {
    "organisation": "Keppel Telecommunications & Transportation Ltd",
    "case_number": "DP-2210-C0378",
    "citation": "[2024] SGPDPC 3",
    "decision_date": "14 May 2024",
    "industry": "Logistics and data centre services",
    "overview": "Keppel Telecommunications & Transportation Ltd failed to delete personal data of approximately 22,659 individuals from a shared server after migrating to cloud storage in May 2020 and again before divesting the subsidiary in July 2022. The undeleted data was subsequently breached through unauthorised access and exfiltration by a threat actor, exposing sensitive information including identification documents, bank account details, and signatures of employees, ex-employees, directors and shareholders.",
    "pdpa_sections": [
      "s.24"
    ],
    "obligations": [
      "Protection Obligation"
    ],
    "individuals_affected": "22659",
    "root_cause": "The Organisation failed to provide specific instructions to delete personal data after the Migration in May 2020 and did not supervise staff who were expected to manage their own data deletion. The same failure occurred during the Divestment in July 2022, when the Organisation overlooked that personal data continued to reside on the shared server despite reminders to transfer files.",
    "outcome": "Financial penalty of $120,000 payable within 30 days. No further directions issued given the remedial actions already taken by the Organisation, which included working with cybersecurity consultants, permanently purging data from the affected server, conducting staff refresher training, and implementing standard operating procedures for IT and cyber due diligence.",
    "penalty": 120000,
    "mitigating": [
      "Prompt actions taken after discovery of the Incident",
      "Investigation handled under Expedited Decision Procedure with full admission of facts and breach",
      "Cooperative with Commission's investigations"
    ],
    "aggravating": [
      "Long period of non-compliance lasting more than 2 years",
      "Systemic shortcomings in data protection processes",
      "Approximately 22,659 affected individuals with up to 7,184 individuals' data potentially exfiltrated",
      "Sensitive personal data affected including identification documents, bank account numbers, and signatures, exposing individuals to identity theft and financial loss risks",
      "Failure to provide clear instructions and supervise staff during both Migration and Divestment processes"
    ],
    "_id": "breach-of-the-protection-obligation-by-keppel-telecommunications-transportation"
  },
  "breach-of-the-protection-obligation-by-academy-of-medicine-singapore": {
    "organisation": "Academy of Medicine Singapore",
    "case_number": "DP-2308-C1326",
    "citation": "[2024] SGPDPCS 4",
    "decision_date": null,
    "industry": "Professional medical education and specialist training",
    "overview": "The Academy of Medicine Singapore's servers were infected with ransomware on 13 July 2023, resulting in the exfiltration of personal data of 6,574 individuals and posting of data on the dark web. The breach included sensitive financial information such as full credit card details with CVV numbers stored in plain text. The Organisation failed to maintain adequate security arrangements including unpatched firewalls, outdated operating systems, and insufficient access controls.",
    "pdpa_sections": [
      "s.24"
    ],
    "obligations": [
      "Protection Obligation"
    ],
    "individuals_affected": "6574",
    "root_cause": "Multiple security lapses including unpatched firewall firmware since July 2021, end-of-life operating systems without support, lack of robust patching processes, failure to implement proper access controls for sensitive financial data, and inadequate threat detection solutions.",
    "outcome": "Financial penalty of $9,000 imposed. Organisation directed to complete remedial actions including security architecture review, network segregation, endpoint hardening, encryption of sensitive data, deletion and non-storage of CVV numbers, implementation of annual security reviews, and submission of completion report within 60 days.",
    "penalty": 9000,
    "mitigating": [
      "Cooperative during investigation",
      "Voluntary admission under Expedited Decision Procedure",
      "First instance of non-compliance with PDPA"
    ],
    "aggravating": [
      "Large number of individuals affected (6,574)",
      "Financial information of 1,083 individuals leaked on dark web",
      "Vulnerable servers with end-of-life operating systems deployed for more than 3 years"
    ],
    "_id": "breach-of-the-protection-obligation-by-academy-of-medicine-singapore"
  },
