  "breach-of-the-protection-obligation-by-cortina-watch": {
    "organisation": "Cortina Watch Pte. Ltd.",
    "case_number": "DP-2306-C1102",
    "citation": "[2024] SGPDPCS 3",
    "decision_date": null,
    "industry": "Retail, import, and export of timepieces, branded pens, and luxury accessories",
    "overview": "Cortina Watch suffered a ransomware attack between 30 April to 4 June 2023 that compromised personal data of 3,953 individuals. The attack exploited inadequate access controls, weak password policies, and the absence of multi-factor authentication on a test VPN account, leading to a breach of section 24 of the PDPA.",
    "pdpa_sections": [
      "s.24"
    ],
    "obligations": [
      "Protection Obligation"
    ],
    "individuals_affected": "3953",
    "root_cause": "A test VPN account with a weak, guessable username was compromised through brute force attacks, allowing threat actors to access a password-protected master password file and laterally move across servers. The organisation lacked reasonable security arrangements including robust password policies, multi-factor authentication, and proper access control hygiene.",
    "outcome": "Directed the organisation to engage a third-party cyber security vendor to conduct a targeted security audit to enhance access control to personal data within 60 days and submit a comprehensive report to PDPC within 7 days of completion. No financial penalty imposed.",
    "penalty": null,
    "mitigating": [
      "Prompt remedial actions taken",
      "Cooperation during investigation",
      "Expedited Breach Decision Procedure admission"
    ],
    "aggravating": [
      "Multiple brute force attacks over extended period",
      "Lack of basic security hygiene on test accounts",
      "Large volume of personal data exfiltrated"
    ],
    "_id": "breach-of-the-protection-obligation-by-cortina-watch"
  },
  "breach-of-the-protection-obligation-by-horizon-fast-ferry-2024-05": {
    "organisation": "Horizon Fast Ferry Pte. Ltd.",
    "case_number": "DP-2304-C0943",
    "citation": "[2024] SGPDPC 1",
    "decision_date": "21 February 2024",
    "industry": "Ferry operator / Transportation",
    "overview": "Horizon Fast Ferry suffered a data breach affecting 108,488 individuals whose personal data including passport details were exfiltrated from its server via misused root account credentials. The organisation failed to implement basic data protection measures including vendor management policies, ICT security policies, and web server security solutions, constituting a serious breach of section 24 of the PDPA.",
    "pdpa_sections": [
      "s.24"
    ],
    "obligations": [
      "Protection Obligation"
    ],
    "individuals_affected": "108488",
    "root_cause": "Valid credentials to the Ubuntu root account remained active and were misused to gain unauthorised access. The IT Supervisor lacked familiarity with the Ubuntu operating system and failed to properly verify that root account access had been disabled when contractors claimed it was no longer accessible.",
    "outcome": "Organisation found in breach of section 24 of the PDPA. Directed to pay financial penalty of S$28,000 within 30 days and provide written confirmation of implementation of remedial measures by 31 March 2024. Remedial measures include PDPA training, written IT vendor agreements, enhanced data protection guidelines, and vendor protocols.",
    "penalty": 28000,
    "mitigating": [
      "Cooperated with Commission during investigations",
      "Took prompt remedial actions",
      "Voluntarily accepted responsibility for the incident",
      "Used Expedited Decision Procedure"
    ],
    "aggravating": [
      "Large number of individuals affected (108,488)",
      "Sensitive personal data (passport details)",
      "Not first instance of non-compliance (previous S$54,000 penalty in 2019 and warning in 2020)",
      "Failed to implement basic levels of data protection policies and practices"
    ],
    "_id": "breach-of-the-protection-obligation-by-horizon-fast-ferry-2024-05"
  },
  "breach-of-the-accountability-and-protection-obligations-by-pplingo-2024": {
    "organisation": "PPLingo Pte Ltd",
    "case_number": "DP-2205-B9761",
    "citation": "[2023] SGPDPC 12",
    "decision_date": "24 October 2023",
    "industry": "Online education / language learning platform",
    "overview": "PPLingo's operations support system was breached via brute force attack on an administrator account with a weak password ('lingoace123'), compromising personal data of 557,144 users including 303,238 minors. The organisation failed to implement adequate password policies, two-factor authentication, and had not appointed a Data Protection Officer despite being required to do so since incorporation.",
    "pdpa_sections": [
      "s.24",
      "s.11(3)"
    ],
    "obligations": [
      "Protection Obligation",
      "Accountability Obligation"
    ],
    "individuals_affected": "557144",
    "root_cause": "Inadequate password policy for administrator account lacking complexity requirements, password expiry, and multi-factor authentication. Administrator password remained unchanged for over 2 years and incorporated the organisation's name and common number sequence, making it vulnerable to brute force attacks.",
    "outcome": "Financial penalty of $74,000 imposed. No further directions necessary given remedial measures already implemented by organisation including password resets, two-factor authentication implementation, appointment of Data Protection Officer, and enhanced security training.",
    "penalty": 74000,
    "mitigating": [
      "No evidence of data exfiltration or misuse",
      "Prompt remedial actions and user notification",
      "Voluntary admission of breach",
      "Cooperative during investigations"
    ],
    "aggravating": [
      "High volume of personal data affected (557,144 individuals)",
      "Sensitive datasets including financial information and minors' data (303,238 minors)",
      "Two separate contraventions of PDPA",
      "Failure to appoint DPO for over 5 years since incorporation"
    ],
    "_id": "breach-of-the-accountability-and-protection-obligations-by-pplingo-2024"
  },
  "voluntary-undertaking-by-yayasan-mendaki": {
    "organisation": "Yayasan Mendaki",
    "case_number": "DP-2210-C0365",
    "citation": null,
    "decision_date": null,
    "industry": "Non-profit organisation / charity",
    "overview": "Yayasan Mendaki suffered a ransomware attack on 27 October 2022 that resulted in the exfiltration of approximately 2.7TB of data from a virtual file server. Although the specific contents of the exfiltrated data could not be determined and none was published or sold on the Dark Web, the PDPC found reasonable grounds to believe the organisation failed to comply with section 24 of the PDPA (Protection Obligation). The organisation entered into a voluntary undertaking to implement comprehensive cybersecurity remediation measures.",
    "pdpa_sections": [
      "s.24"
    ],
    "obligations": [
      "Protection Obligation"
    ],
    "individuals_affected": null,
    "root_cause": "The ransomware attack exploited vulnerabilities in the organisation's on-premises network infrastructure, including inadequate access controls, insufficient endpoint protection, and weak authentication mechanisms. The organisation lacked sufficient technical safeguards to detect and prevent large-scale data exfiltration.",
    "outcome": "Voluntary undertaking under section 48L of the PDPA suspending the investigation. Yayasan Mendaki committed to completing a 16-item remediation plan by 31 December 2023, including phishing awareness training, software patching, firewall policy updates, migration to cloud servers, two-factor authentication, VPN implementation, and password policy strengthening. The organisation must provide a signed declaration within 14 days of completion. The PDPC will publish the undertaking and summary of findings.",
    "penalty": 0,
    "mitigating": [
      "Immediate remedial actions taken",
      "Cooperative with PDPC investigation",
      "Proactive notification of affected individuals",
      "Cloud infrastructure not affected",
      "No evidence of data publication or sale"
    ],
    "aggravating": [],
    "_id": "voluntary-undertaking-by-yayasan-mendaki"
  },
