    "case_number": "DP-2303-C0848",
    "citation": "[2024] SGPDPCS 2",
    "decision_date": null,
    "industry": "Payroll service provider / Software as a Service (SaaS)",
    "overview": "Payroll2U suffered a ransomware attack on 29 December 2022 that resulted in the exfiltration of 81.95 GB of personal data belonging to 5,640 employees of its clients, including names, bank account numbers, salary information, NRIC numbers, addresses, dates of birth and email addresses. The attack exploited inadequate access controls, lack of multi-factor authentication, excessive administrator privileges, and poor endpoint protection practices.",
    "pdpa_sections": [
      "s.24"
    ],
    "obligations": [
      "Protection Obligation"
    ],
    "individuals_affected": "5640",
    "root_cause": "A single compromised user account was used for Remote Desktop Protocol access to five servers in the organisation's AWS environment. The compromised user had installed an unlicensed Windows Operating System that removed endpoint protection and allowed unauthorised access to developer and shared drives containing personal data.",
    "outcome": "Financial penalty of $4,000 payable within 30 days. The organisation must implement reasonable access controls including multi-factor authentication, network segmentation, restricted administrator rights, endpoint protection, firewall configuration improvements, and regular access reviews.",
    "penalty": 4000,
    "mitigating": [
      "Cooperative during investigation",
      "Voluntary admission under Expedited Breach Decision Procedure",
      "First instance of non-compliance with PDPA"
    ],
    "aggravating": [
      "Large volume of sensitive personal data affected",
      "Role as payroll service provider handling sensitive financial and identity information"
    ],
