    "outcome": "The Commissioner found the organisation in breach of section 24 of the PDPA and directed it to pay a financial penalty of S$10,000 within 30 days. No further directions were imposed given the remediation measures already implemented.",
    "penalty": 10000,
    "mitigating": [
      "Cooperative during investigation",
      "Prompt remedial actions implemented",
      "Unauthorised disclosure limited to single complainant"
    ],
    "aggravating": [
      "Data exposed to risk of unauthorised disclosure for approximately 6 months"
    ],
    "_id": "breach-of-the-protection-obligation-by-mdis-corporation"
