  "breach-of-the-protection-obligation-by-singtel": {
    "organisation": "Singapore Telecommunications Limited",
    "case_number": "DP-1802-B1732",
    "citation": "[2019] SGPDPC 49",
    "decision_date": "31 December 2019",
    "industry": "Telecommunications",
    "overview": "During a database migration from an existing billing system to a new system, a technical issue caused 750 mobile subscribers' personal data to be at risk of unauthorised access, with 39 subscribers' data actually accessed by other users. The incident occurred over 11 hours on 20 February 2018 when the Master Routing Database timed out and incorrectly routed queries containing historical mobile numbers that had been reassigned to other subscribers.",
    "pdpa_sections": [
      "s.24"
    ],
    "obligations": [
      "Protection Obligation"
    ],
    "individuals_affected": "750",
    "root_cause": "Insufficient testing during system migration failed to identify that dummy mobile numbers (temporary numbers used for number porting) could be reassigned to new subscribers. When MRD queries timed out during migration, the system defaulted to the old system and incorrectly retrieved and displayed personal data associated with reassigned historical numbers.",
    "outcome": "Organisation found in breach of section 24 of the PDPA for failing to conduct adequately scoped tests and failing to anticipate likely failure scenarios such as session timeouts. Directed to pay a financial penalty of $9,000 within 30 days. No further remedial directions issued as migration was completed and temporary fix implemented.",
    "penalty": 9000,
    "mitigating": [
      "Organisation was cooperative during investigations",
      "Prompt action taken to mitigate impact by implementing temporary fix within 11 hours",
      "Although 750 individuals' data at risk, only 39 actually subject to unauthorised disclosure"
    ],
    "aggravating": [],
    "_id": "breach-of-the-protection-obligation-by-singtel"
  },
