    "mitigating": [
      "Personal data disclosed to only 1 person",
      "Limited sensitivity of personal data except for one NRIC disclosure",
      "Organisation took remedial actions post-breach",
      "Organisation fully cooperative in investigation"
    ],
    "aggravating": [
      "No measures to ensure instruction compliance",
      "No data protection training provided",
      "Inadequate supervision of new employee",
      "Generic data protection policy without practical guidance",
      "Breach was foreseeable and preventable"
    ],
